    {
        maxHealth = 100; // Set your maximum health here
        currentHealth = maxHealth; // Assuming full health at start
        CalculateHealthThresholds(); // Calculate the health thresholds based on the number of objects
    }

    private void CalculateHealthThresholds()
    {
        if (objectsToActivate.Length == 0) return;

        healthThresholds = new int[objectsToActivate.Length];

        // Calculate evenly distributed thresholds for each object. This assumes an even spread.
        for (int i = 0; i < objectsToActivate.Length; i++)
        {
            healthThresholds[i] = maxHealth - (maxHealth / objectsToActivate.Length) * i;
        }
    }

    // Call this function whenever health changes
    public void UpdateHealth(int newHealth)
    {
        currentHealth = newHealth;

        for (int i = 0; i < healthThresholds.Length; i++)
        {
            if (currentHealth <= healthThresholds[i])
            {
                // Activate the object at this threshold and deactivate the higher ones
